import{_ as e,o,c as t,a2 as l}from"./chunks/framework.BWuWLRhz.js";const d="/assets/22-progressive-disclosure@2x.OwexZN84.png",h=JSON.parse('{"title":"22 · Agent Skills 技能：把一套活儿打包，教会 Codex 自己接","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"codex/22-skills.md","filePath":"codex/22-skills.md"}'),i={name:"codex/22-skills.md"};function n(a,s,c,r,p,g){return o(),t("div",null,[...s[0]||(s[0]=[l(`<h1 id="_22-·-agent-skills-技能-把一套活儿打包-教会-codex-自己接" tabindex="-1">22 · Agent Skills 技能：把一套活儿打包，教会 Codex 自己接 <a class="header-anchor" href="#_22-·-agent-skills-技能-把一套活儿打包-教会-codex-自己接" aria-label="Permalink to &quot;22 · Agent Skills 技能：把一套活儿打包，教会 Codex 自己接&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇〔<a href="./21-subagents">21 子代理（Subagents）</a>〕讲的是「把一个重活拆出去、丢给一个独立上下文的小助手干完再收结果」。这一篇换个角度：不拆任务，而是<strong>封装能力</strong>——把一套你反复交代的固定流程打包成 Agent Skills，让 Codex 在该用的时候自己调出来。下一篇〔<a href="./23-plugins">23 插件（Plugins）</a>〕再讲怎么把这身本事打包、分发给别人装。</p></blockquote><p>我翻了一下 OpenAI 官方那个 <code>github.com/openai/skills</code> 仓库。</p><p>里头一个 Skill，骨架精简到<strong>只有一个 <code>SKILL.md</code> 文件</strong>就能跑——上面两道横线框一段元数据，下面写几行「该咋干」的说明，齐活。可就这么个不起眼的小目录，官方给它的定位是「<strong>可复用工作流的编写格式</strong>」（the authoring format for reusable workflows）：你把一套活儿写进去，Codex 之后该用就用，不用你每次把步骤重敲一遍。</p><p>很多人第一次听 Skill，反应是「这不就是斜杠命令换了个壳？我第 12 篇刚学的 <code>/review</code> 不也是打一下就跑」。说句实话，这个理解差了一层。<strong>斜杠命令是你主动喊它才动；Skill 你可以不喊——Codex 看你这活儿对得上某个 Skill 的描述，自己就把它调出来了，而且平时几乎不占你的上下文。</strong></p><p>这一篇，我把 Skill 到底是什么、凭什么能塞一堆还不撑爆上下文、放哪、怎么触发、怎么自己写，一次给你讲透。事实一律以 Codex <a href="https://developers.openai.com/codex/skills" target="_blank" rel="noreferrer">官方文档</a> 为准——网上有些老教程把 Skill 的目录路径、字段名写错了，下面我会专门拎出来提醒你别踩。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>Skill 到底是什么——一个 <code>SKILL.md</code> 加可选脚本 / 资源，怎么就成了 Codex 的一项本事</li><li>它的命门「渐进式披露」：为什么平时只占一句描述、用到才展开全文，省上下文的秘密全在这</li><li>两种触发方式（显式 <code>$</code> 喊名字 / 隐式按描述自动匹配）差在哪，怎么写描述才匹配得准</li><li>Skill 该放哪个目录（<code>.agents/skills</code> 那套，<strong>不是</strong> <code>~/.codex/skills</code>），同名了会咋样</li><li>怎么用 <code>$skill-creator</code> 三五句话生成一个、怎么用 <code>$skill-installer</code> 装现成的、怎么禁用某个</li></ul><hr><h2 id="_01-先搞懂-skill-到底是个什么东西" tabindex="-1">01 先搞懂：Skill 到底是个什么东西 <a class="header-anchor" href="#_01-先搞懂-skill-到底是个什么东西" aria-label="Permalink to &quot;01 先搞懂：Skill 到底是个什么东西&quot;">​</a></h2><p>先给结论：<strong>一个 Skill，本质就是一个带 <code>SKILL.md</code> 文件的目录，外加可选的脚本和参考资料，打包成一身「专项本事」交给 Codex</strong>。官方原话——「一个 Skill 是一个带 <code>SKILL.md</code> 文件、外加可选脚本和参考资料的目录」。</p><p>为什么需要它？因为你跟 Codex 干活，总有那么几套流程是<strong>反复交代的</strong>。比如我每次让它提交代码，都得叮嘱「先跑测试、commit 信息用中文、前缀按 <code>feat:</code>／<code>fix:</code> 来」——同一段话，我去年估摸着敲了不下三十遍。这种「说明书级别」的重复，就是 Skill 该接管的。</p><p><strong>类比：乐高的「拼装说明书」。</strong> 你买一盒乐高，盒子里那本图纸不替你拼，但它一步步标清楚「先装底盘、再上四个轮子、最后扣车顶」。照着拼，谁来都能拼对、拼得一样。Skill 就是你写给 Codex 的那本图纸：把一套固定步骤（「总结未提交的改动并标出风险」）写进 <code>SKILL.md</code>，之后这套流程就成了 Codex 随手能照着拼的一个动作，你不用每次把图纸重画一遍。</p><p><code>SKILL.md</code> 长什么样？最小骨架就两部分，官方给的模板是这样：</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skill-name</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">说清这个技能该在什么时候触发、什么时候不该触发。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">供 Codex 遵循的技能指令写在这里。</span></span></code></pre></div><p>上面那个 <code>---</code> 框起来的部分叫 <strong>YAML frontmatter</strong>（前置元数据，写在文件开头两道 <code>---</code> 之间的配置区），官方规定它<strong>必须含 <code>name</code> 和 <code>description</code> 两个字段</strong>：<code>name</code> 是这身本事的名字（也是你以后用 <code>$</code> 喊它时的名字），<code>description</code> 告诉 Codex 这个 Skill 是干啥的、啥时候该用。下面的 markdown 正文，是 Codex 真正调用时照着做的<strong>说明</strong>。</p><blockquote><p>⚠️ 这里有个<strong>新手最容易被老教程带歪的坑</strong>：有些非官方资料里 frontmatter 写了个 <code>trigger:</code> 字段（说是「触发关键词」），还教你把<strong>自己手写</strong>的 Skill 放进 <code>~/.codex/skills/</code>。<strong>官方文档里没有 <code>trigger</code> 这个字段</strong>，触发靠的是 <code>description</code> 的语义匹配（下文细说）；<strong>手写 / 仓库级 Skill 的目录是 <code>.agents/skills</code> 那一套</strong>（第 04 节讲），不是 <code>~/.codex/skills/</code>。<strong>例外要先说清</strong>：第 05 节讲的 <code>$skill-installer</code> 这个<strong>官方安装器</strong>装精选 Skill 时，确实会把它放到 <code>$CODEX_HOME/skills/&lt;名字&gt;</code>（默认 <code>~/.codex/skills/&lt;名字&gt;</code>）——那是 Codex 当前版本下安装器<strong>自己的行为</strong>，跟「老教程让你手动把自建 skill 塞这儿」不是一回事。<strong>自己手写一律走 <code>.agents/skills</code>；<code>$skill-installer</code> 装的留在 <code>~/.codex/skills/</code> 别动它</strong>。</p></blockquote><p>一个 Skill 不止 <code>SKILL.md</code> 一个文件，它是个<strong>目录</strong>。除了必需的 <code>SKILL.md</code>，还能带脚本和参考资料：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-skill/</span></span>
<span class="line"><span>├── SKILL.md          # 主说明（必需，含 name + description）</span></span>
<span class="line"><span>├── scripts/          # 可选：可执行脚本（要确定性行为、或调外部工具时用）</span></span>
<span class="line"><span>└── references/       # 可选：参考文档，Codex 执行时按需查阅</span></span></code></pre></div><p>只有 <code>SKILL.md</code> 是必需的，其余都可选。这也引出官方一条很实在的取舍——<strong>能用指令说清的就别写脚本，除非你需要「确定性行为」或得调外部工具</strong>。说白了：让 Codex 照着自然语言步骤干，比硬塞一个脚本更灵活；只有那种「这一步必须分毫不差地跑」或者「得调个命令行工具」的活儿，才值得把脚本捆进来。</p><p><strong>三个真实场景，你立刻能想到 Skill 能干嘛：</strong></p><ul><li>你每次让 Codex 提交代码，都要叮嘱那套「先测试、中文 commit、前缀按约定」——写进一个 <code>commit</code> Skill，以后一句话搞定。</li><li>团队约定了一套 API 写法（RESTful 命名、统一错误格式、必带参数校验）——写成 <code>api-conventions</code> Skill，谁写接口它自动按这套来。</li><li>你有一套固定的「发版前自查清单」（更新 changelog、打 tag、跑冒烟测试）——写成 Skill，发版那天一句话拉起来走流程。</li></ul><blockquote><p>💡 一句话总结：Skill 就是「带 <code>SKILL.md</code>（<code>name</code> + <code>description</code> + 怎么做）的目录 + 可选脚本 / 参考资料」打成的一身本事——<strong>写一次，之后 Codex 随手就能调</strong>；能用指令说清的别急着写脚本。</p></blockquote><hr><h2 id="_02-命门-渐进式披露-省上下文的秘密" tabindex="-1">02 命门：渐进式披露，省上下文的秘密 <a class="header-anchor" href="#_02-命门-渐进式披露-省上下文的秘密" aria-label="Permalink to &quot;02 命门：渐进式披露，省上下文的秘密&quot;">​</a></h2><p>这是整篇最该吃透的一节。<strong>Skill 凭什么能装一大堆，却几乎不占你的上下文？</strong> 答案就一个词：渐进式披露（progressive disclosure，意思是「按需逐步展开」，不相关时不加载全文）。</p><p>先说为什么这事关键。你回想第 02 篇讲的上下文窗口——Codex 的「工作台」就那么大，塞进去的每个字都在花预算、都在挤占它思考的余地。要是每个 Skill 的全文一开会话就全堆进去，装上十个八个，你的工作台就废了一半。</p><p><strong>类比：自助餐厅的「菜品牌子」和后厨。</strong> 你端着盘子走过取餐台，每道菜前面只立一块<strong>小牌子</strong>——菜名加一句话（「麻婆豆腐 · 微辣」）。你扫一眼就知道有什么，但牌子背后那口锅、那套火候配料，<strong>没轮到这道菜，你压根接触不到</strong>。等你真夹了麻婆豆腐，后厨那套详细做法才在它那边「展开」。Skill 就这么运作，官方把这两阶段说得很清楚：</p><blockquote><p>Codex 启动时，只带着每个技能的名称、描述和文件路径。只有当它决定使用某个技能时，才会加载该技能完整的 <code>SKILL.md</code> 指令。</p></blockquote><p>翻成大白话就是：</p><ul><li><strong>平时</strong>：上下文里每个 Skill 只占「名字 + 一句 description + 文件路径」（取餐台的小牌子）。</li><li><strong>选中时</strong>：Codex 判断某个 Skill 对得上当前任务，<strong>才把那一个 Skill 的完整 <code>SKILL.md</code> 正文</strong>读进来（端走那道菜的详细做法）。</li></ul><p>这就是为什么你可以放心往 Skill 正文里写长篇检查清单、详细参考——<strong>用到之前，它几乎不花成本</strong>。</p><p><img src="`+d+'" alt="Skills 渐进式披露两阶段"></p><p>两列并排：左边阶段一，启动时每个 Skill 只占「名称 + 一句描述 + 文件路径」；右边阶段二，只有被任务命中的那一个 Skill 才把完整 <code>SKILL.md</code> 展开读入，其余照旧只占一行。</p><p>不过这个「初始清单」也不是无限白送的——官方给了它一个<strong>字符预算</strong>，这点很多人不知道，栽过坑：</p><blockquote><p>为了不挤占提示词的其余空间，这份初始清单被限制在模型上下文窗口的<strong>约 2%</strong>，或上下文窗口未知时的 <strong>8,000 个字符</strong>。如果装了很多技能，Codex 会<strong>先缩短描述</strong>；对于极大的技能集，<strong>部分技能可能被从初始清单里省略</strong>，Codex 会给出警告。</p></blockquote><p>注意，这个预算<strong>只管初始清单</strong>——Codex 真选中某个 Skill 后，照样会完整读它的 <code>SKILL.md</code>。这条规则有个直接的实战含义，记牢：<strong>你的 <code>description</code> 要把核心用例和触发关键词放在最前面</strong>。万一装的 Skill 多到描述被压缩，前置的关键词还能保住、匹配照样准；要是关键词埋在描述末尾，一压缩就被削没了——这跟我第 11 篇讲 <code>AGENTS.md</code> 那个「把唯一有用的规矩埋在第 140 行」是同一个教训：<strong>重要的信息要前置</strong>。</p><blockquote><p>💡 一句话总结：渐进式披露 = 平时只露「名称 + 一句描述」、用到才展开完整 <code>SKILL.md</code>，所以装再多也不撑上下文；但初始清单有字符预算（约 2% 或 8000 字符），<strong>描述务必把核心触发词前置</strong>，免得被压缩时削没了。</p></blockquote><hr><h2 id="_03-两种触发方式-显式喊名字-vs-隐式自动匹配" tabindex="-1">03 两种触发方式：显式喊名字 vs 隐式自动匹配 <a class="header-anchor" href="#_03-两种触发方式-显式喊名字-vs-隐式自动匹配" aria-label="Permalink to &quot;03 两种触发方式：显式喊名字 vs 隐式自动匹配&quot;">​</a></h2><p>知道 Skill 怎么省上下文了，那它到底怎么被「调出来」？官方给了<strong>两条路</strong>，搞清这俩的差别，是用好 Skill 的关键。</p><p><strong>类比：叫外卖的两种点法。</strong> 一种是你<strong>点名要某家店</strong>——「就要楼下那家黄焖鸡」，平台直接派给它，不用猜。另一种是你<strong>只说需求</strong>——「来份下饭的、辣一点的」，平台根据你这句话去匹配最合适的店。Skill 的两种触发，正好对应这两种点法。</p><h3 id="显式调用-你点名喊它" tabindex="-1">显式调用：你点名喊它 <a class="header-anchor" href="#显式调用-你点名喊它" aria-label="Permalink to &quot;显式调用：你点名喊它&quot;">​</a></h3><p>第一种是<strong>显式调用（explicit invocation）</strong>——你在提示词里直接把这个 Skill 点出来。官方给的操作：在 CLI 或 IDE 里，<strong>跑 <code>/skills</code> 命令，或者输入 <code>$</code> 符号来提及一个技能</strong>。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$commit</span></span></code></pre></div><p>打一个 <code>$</code>，会弹出可选的 Skill 列表，选中（或直接把名字打全）就是点名让它接管。显式调用时 Codex <strong>不做任何匹配判断</strong>，直接加载完整 <code>SKILL.md</code> 照着干——你说要哪个就是哪个，最稳妥。</p><blockquote><p>⚠️ 又一个老教程的坑：有资料里写显式调用是 <code>@skill-name</code>。<strong>官方的写法是 <code>$</code>（配合 <code>/skills</code>）</strong>，不是 <code>@</code>。别记混了。</p></blockquote><h3 id="隐式调用-它按描述自己匹配" tabindex="-1">隐式调用：它按描述自己匹配 <a class="header-anchor" href="#隐式调用-它按描述自己匹配" aria-label="Permalink to &quot;隐式调用：它按描述自己匹配&quot;">​</a></h3><p>第二种是<strong>隐式调用（implicit invocation）</strong>——你压根不提 Skill 名，正常说人话，Codex 拿你这句话去比对每个 Skill 的 <code>description</code>，对上了就自动把那个 Skill 调出来。官方原话：「当你的任务匹配某个技能的 <code>description</code> 时，Codex 可以自己选用该技能。」</p><p>这是 Skill 最舒服的地方：<strong>你不用记 <code>$什么什么</code>，描述写得好，需求一说它自己就接住了</strong>。但这也把球踢回给了 <code>description</code>——官方说得很直白：</p><blockquote><p>因为隐式匹配依赖 <code>description</code>，所以要写<strong>简洁、范围清晰、边界明确</strong>的描述。把关键用例和触发词前置，这样即使描述被缩短，Codex 仍能匹配到这个技能。</p></blockquote><p>我自己写第一个 Skill 时就吃过亏：description 写成「帮助处理代码相关任务」——太泛了，结果它要么什么活儿都想往这个 Skill 上靠、要么该用时反而没匹配上。后来改成「<strong>总结未提交的改动并标出风险。当用户问『改了啥』『想要提交信息』『帮我看看 diff』时使用</strong>」，把用户真会说出口的话直接写进去，匹配立刻准了。<strong>description 不是写给人看的简介，是写给匹配算法的钩子。</strong></p><p>两种触发方式摆一起对比：</p><table tabindex="0"><thead><tr><th>维度</th><th>显式调用（<code>$</code> / <code>/skills</code>）</th><th>隐式调用（按描述匹配）</th></tr></thead><tbody><tr><td>怎么触发</td><td>你打 <code>$</code> 点名，或跑 <code>/skills</code> 选</td><td>正常说需求，Codex 自己匹配</td></tr><tr><td>Codex 做不做判断</td><td>不做，<strong>点名即用</strong></td><td>做，<strong>拿你的话比对 description</strong></td></tr><tr><td>准不准取决于</td><td>你点对没有</td><td><strong>description 写得好不好</strong></td></tr><tr><td>最适合</td><td>想精确控制用哪个、用哪一次</td><td>让 Codex「该用就用」，省得记名字</td></tr><tr><td>想关掉吗</td><td>关不掉（点名永远有效）</td><td>可关（见第 05 节 <code>allow_implicit_invocation</code>）</td></tr></tbody></table><blockquote><p>💡 一句话总结：显式调用靠 <code>$</code> 或 <code>/skills</code> 点名、最稳妥；隐式调用靠 <code>description</code> 语义匹配、最省心——<strong>而隐式准不准全压在 description 上</strong>，把核心触发词写成「用户真会说出口的话」并前置，是写 Skill 的头等功夫。</p></blockquote><hr><h2 id="_04-放哪决定谁能用-agents-skills-那套目录" tabindex="-1">04 放哪决定谁能用：<code>.agents/skills</code> 那套目录 <a class="header-anchor" href="#_04-放哪决定谁能用-agents-skills-那套目录" aria-label="Permalink to &quot;04 放哪决定谁能用：`.agents/skills` 那套目录&quot;">​</a></h2><p>知道是什么、怎么触发了，那自己写的 Skill 放哪儿？这一节是<strong>最容易被网上老教程带错的地方</strong>，照官方表抄，别凭印象。</p><p>官方说 Codex 从<strong>仓库（REPO）、用户（USER）、管理员（ADMIN）、系统（SYSTEM）</strong> 四个层级读取技能。其中仓库层有个特别之处：<strong>Codex 会从你启动它的当前目录，一路往上扫到仓库根，沿途每一级的 <code>.agents/skills</code> 都读</strong>。完整位置表如下：</p><table tabindex="0"><thead><tr><th>作用范围</th><th>放哪</th><th>谁 / 哪里能用</th></tr></thead><tbody><tr><td><strong>REPO（当前目录）</strong></td><td><code>$CWD/.agents/skills</code></td><td>你启动 Codex 的那个目录——适合某个模块 / 微服务专属的技能</td></tr><tr><td><strong>REPO（上级目录）</strong></td><td><code>$CWD/../.agents/skills</code></td><td>当前目录的上层——适合嵌套结构里某块共享区域</td></tr><tr><td><strong>REPO（仓库根）</strong></td><td><code>$REPO_ROOT/.agents/skills</code></td><td>仓库最顶层——整个仓库所有子目录都能用的基础技能</td></tr><tr><td><strong>USER（个人）</strong></td><td><code>$HOME/.agents/skills</code></td><td>你这个用户在<strong>任何</strong>仓库里都能用</td></tr><tr><td><strong>ADMIN（机器级）</strong></td><td><code>/etc/codex/skills</code></td><td>这台机器 / 容器上所有用户共享（SDK 脚本、自动化、管理员默认技能）</td></tr><tr><td><strong>SYSTEM（系统内置）</strong></td><td>由 OpenAI 随 Codex 打包</td><td>所有人启动 Codex 就有（如 <code>skill-creator</code>、plan 类技能）</td></tr></tbody></table><blockquote><p>⚠️ <strong>划重点防踩坑</strong>：上面这张表讲的是<strong>你自己手写</strong>的 Skill 该放哪——仓库级 <code>.agents/skills</code>、个人级 <code>$HOME/.agents/skills</code>，<strong>不要手动把自建 Skill 塞进</strong> <code>~/.codex/skills/</code> （<code>~/.codex/</code> 是放 <code>config.toml</code> 这类<strong>配置</strong>的地方，第 05 节会用到）。</p><p>但有个<strong>例外</strong>得交代清楚，免得跟第 05 节自相矛盾：用 <code>$skill-installer</code> 安装的<strong>精选 Skill</strong>（curated skill），当前版本下安装器会把它装到 <code>$CODEX_HOME/skills/&lt;名字&gt;</code>，默认就是 <code>~/.codex/skills/&lt;名字&gt;</code>——<strong>那是安装器自己的行为，Codex 也会从那里加载</strong>。所以记住：「<strong>自己手写的走 <code>.agents/skills</code>、安装器装的留在 <code>~/.codex/skills/</code> 别去碰</strong>」，这俩位置都是 Codex 在用，不是非此即彼的对错。这跟第 11 篇 <code>AGENTS.md</code> 那套发现链是两码事，别混。</p></blockquote><p>逻辑其实很直观：<strong>只有你自己用、跨项目通用的</strong>（比如你个人的 commit 习惯），放用户级 <code>$HOME/.agents/skills</code>；<strong>这个仓库专属、想让团队都用的</strong>（比如本项目的发版流程），放仓库级 <code>.agents/skills</code> 并提交进版本库，队友拉下来就有。Mac / Linux 上 <code>$HOME</code> 就是你的主目录；Windows 用户注意，官方这套路径以类 Unix 写法给出，实际以你本机 Codex 实际读取的位置为准。</p><p>那<strong>两个 Skill 重名了</strong>会咋样？官方说得很明确——<strong>Codex 不会合并它们，两个都会出现在技能选择器里</strong>。这跟第 11 篇 <code>AGENTS.md</code> 的「就近覆盖」不一样：<code>AGENTS.md</code> 是拼接 + 冲突时近的赢，Skill 重名则是<strong>两个并存、都列出来让你挑</strong>。所以官方建议：<strong>不同作用范围之间别用相同的技能名</strong>，免得选的时候自己都分不清哪个是哪个。</p><p>还有个贴心细节：<strong>Codex 会自动侦测技能文件的变更</strong>——你改了 <code>SKILL.md</code> 一般马上生效。万一改完没反应，官方给的招就一个字：<strong>重启 Codex</strong>。</p><blockquote><p>💡 一句话总结：技能放 <code>.agents/skills</code>（仓库级，会从当前目录往上扫到仓库根）或 <code>$HOME/.agents/skills</code>（用户级），<strong>不是 <code>~/.codex/skills</code></strong>；同名不合并、两个都列出来，所以跨层别重名；改完一般自动生效，不行就重启。</p></blockquote><hr><h2 id="_05-上手-用-skill-creator-生成、-skill-installer-安装、按需禁用" tabindex="-1">05 上手：用 <code>$skill-creator</code> 生成、<code>$skill-installer</code> 安装、按需禁用 <a class="header-anchor" href="#_05-上手-用-skill-creator-生成、-skill-installer-安装、按需禁用" aria-label="Permalink to &quot;05 上手：用 `$skill-creator` 生成、`$skill-installer` 安装、按需禁用&quot;">​</a></h2><p>光懂原理不够，这一节落到三件最实操的事：怎么快速造一个 Skill、怎么装别人现成的、怎么临时关掉某个。</p><h3 id="造-优先用内置的-skill-creator" tabindex="-1">造：优先用内置的 <code>$skill-creator</code> <a class="header-anchor" href="#造-优先用内置的-skill-creator" aria-label="Permalink to &quot;造：优先用内置的 `$skill-creator`&quot;">​</a></h3><p>官方的建议很干脆——<strong>先用内置的创建器</strong>，别一上来手搓。在 CLI 或 IDE 里输入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$skill-creator</span></span></code></pre></div><p>它会跟你做个简短问答，官方说就问三件事：<strong>这个技能做什么？什么时候该触发？纯指令就够还是要带脚本？</strong>（最后一项<strong>默认推荐纯指令</strong>，简洁好维护——呼应第 01 节那条「能用指令别写脚本」。）答完它就把目录骨架和 <code>SKILL.md</code> 给你生成好。这是我现在写新 Skill 的默认起手式：让它先搭架子，我再改细节，比对着文档从零敲一个 <code>SKILL.md</code> 省事多了。</p><p>当然你也可以<strong>手动建</strong>——按第 01 节那个模板，建个目录、写个含 <code>name</code> + <code>description</code> 的 <code>SKILL.md</code> 就行，本质和创建器产出的一样。</p><h3 id="装-用-skill-installer-拉现成的" tabindex="-1">装：用 <code>$skill-installer</code> 拉现成的 <a class="header-anchor" href="#装-用-skill-installer-拉现成的" aria-label="Permalink to &quot;装：用 `$skill-installer` 拉现成的&quot;">​</a></h3><p>不想自己写、想用别人做好的？官方提供了 <code>$skill-installer</code> 来装内置之外的精选技能。比如装 Linear（一个项目管理工具）的技能：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$skill-installer linear</span></span></code></pre></div><p>你还能让安装器<strong>从别的仓库下载技能</strong>。装完 Codex 一般自动侦测到，没出现就重启。</p><blockquote><p>ℹ️ <strong>它装到哪？</strong> 当前版本（codex-cli 0.142.x）的安装位置是 <code>$CODEX_HOME/skills/&lt;名字&gt;</code>，默认就是 <code>~/.codex/skills/&lt;名字&gt;</code>——<strong>注意这跟第 04 节「自己手写的 Skill 放 <code>.agents/skills</code>」不冲突，那是「手写」，这是「安装器装」</strong>，两条路 Codex 都会扫。<strong>具体安装位置以当前 <code>$skill-installer</code> 输出和官方文档为准</strong>，后续版本可能调整。</p></blockquote><blockquote><p>ℹ️ 官方对 <code>$skill-installer</code> 的定位是「<strong>本地试用和实验</strong>」。要是你想把<strong>自己写的</strong>技能正经分发给别人、或者把好几个技能打包，官方推荐走 <strong>Plugins（插件）</strong> 那条路——这正好是下一篇〔23 插件〕的主题。一句话先记着：<strong>Skill 是「编写格式」，Plugin 是「分发格式」</strong>；先用 Skill 把工作流设计好，要给别人装时再打包成插件。</p></blockquote><h3 id="禁用-不删文件-关掉就行" tabindex="-1">禁用：不删文件，关掉就行 <a class="header-anchor" href="#禁用-不删文件-关掉就行" aria-label="Permalink to &quot;禁用：不删文件，关掉就行&quot;">​</a></h3><p>某个技能（可能是装来的，也可能是系统内置的）你暂时不想让它出现，<strong>又不舍得删</strong>，怎么办？官方给的办法是在 <code>~/.codex/config.toml</code>（Codex 的用户级配置文件，注意是 <code>.codex</code> 不是 <code>.agents</code>）里加一段：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 文件路径：~/.codex/config.toml</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">skills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">config</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">path = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/path/to/skill/SKILL.md&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enabled = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>把 <code>path</code> 填成那个技能 <code>SKILL.md</code> 的实际路径，<code>enabled = false</code> 一关，它就不参与了。<strong>改完 <code>config.toml</code> 记得重启 Codex</strong> 才生效。这招在「装的技能太多、初始清单字符预算被挤爆」时特别有用——第 02 节说过预算有限，把当前用不上的技能临时禁掉，给常用的腾地方。</p><h3 id="进阶-关掉隐式触发-agents-openai-yaml" tabindex="-1">进阶：关掉隐式触发（<code>agents/openai.yaml</code>） <a class="header-anchor" href="#进阶-关掉隐式触发-agents-openai-yaml" aria-label="Permalink to &quot;进阶：关掉隐式触发（`agents/openai.yaml`）&quot;">​</a></h3><p>如果你想给 Skill 配点高级属性——比如在 Codex App 里的显示名 / 图标、声明依赖的工具、或者<strong>关掉它的隐式触发</strong>——官方支持在技能目录里放一个 <code>agents/openai.yaml</code>。最常用的一项是这个：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 文件路径：&lt;技能目录&gt;/agents/openai.yaml</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">policy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  allow_implicit_invocation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p><code>allow_implicit_invocation</code> <strong>默认是 <code>true</code></strong>（即默认允许隐式匹配）；设成 <code>false</code> 后，<strong>Codex 不再根据你的提示词隐式调用它，但显式的 <code>$技能名</code> 调用照样有效</strong>。这正是第 03 节那张表里「隐式可关、显式关不掉」的开关。什么时候用？比如一个有副作用、你想亲手掐时机的技能（像「发布上线」），你肯定不希望 Codex「看你代码像写好了」就自作主张隐式触发——给它 <code>allow_implicit_invocation: false</code>，锁成只能你 <code>$</code> 点名。</p><p>把这一节的几个动作和它们的「住址」理一张表，别再放错地方：</p><table tabindex="0"><thead><tr><th>你想干啥</th><th>用什么</th><th>文件 / 命令在哪</th></tr></thead><tbody><tr><td>快速造一个新 Skill</td><td><code>$skill-creator</code></td><td>CLI / IDE 里直接打</td></tr><tr><td>装别人现成的 Skill</td><td><code>$skill-installer &lt;名字&gt;</code></td><td>CLI / IDE 里直接打</td></tr><tr><td>临时禁用某个 Skill</td><td><code>[[skills.config]]</code></td><td><code>~/.codex/config.toml</code></td></tr><tr><td>关掉某 Skill 的隐式触发</td><td><code>allow_implicit_invocation: false</code></td><td>该技能目录的 <code>agents/openai.yaml</code></td></tr><tr><td>放自己写的 Skill 文件</td><td>建目录 + <code>SKILL.md</code></td><td><code>.agents/skills</code> 或 <code>$HOME/.agents/skills</code></td></tr><tr><td>查 <code>$skill-installer</code> 装到哪</td><td>上一节那个安装器</td><td><code>$CODEX_HOME/skills/&lt;名字&gt;</code>（默认 <code>~/.codex/skills/&lt;名字&gt;</code>）</td></tr></tbody></table><blockquote><p>💡 一句话总结：造用 <code>$skill-creator</code>（默认纯指令）、装用 <code>$skill-installer</code>、禁用在 <code>~/.codex/config.toml</code> 写 <code>[[skills.config]]</code>、关隐式触发在技能目录放 <code>agents/openai.yaml</code> 设 <code>allow_implicit_invocation: false</code>——<strong>注意一条对照：自己手写的 Skill 走 <code>.agents/skills</code>，<code>$skill-installer</code> 装的精选 Skill 在 <code>~/.codex/skills/</code> 由它管，两条路 Codex 都会扫，别混着用</strong>。</p></blockquote><hr><h2 id="_06-动手-3-分钟造一个-skill-看它「自己被叫出来」" tabindex="-1">06 动手：3 分钟造一个 Skill，看它「自己被叫出来」 <a class="header-anchor" href="#_06-动手-3-分钟造一个-skill-看它「自己被叫出来」" aria-label="Permalink to &quot;06 动手：3 分钟造一个 Skill，看它「自己被叫出来」&quot;">​</a></h2><p>光看不练记不住。下面这套最小操作，不写任何脚本，就让你亲眼看到两件事：<strong>Skill 怎么被一句人话隐式触发、怎么用 <code>$</code> 显式点名</strong>。全程在一个空目录就能跑。</p><blockquote><p>平台差异先说清：下面建目录的 <code>mkdir</code> 在 <strong>Mac / Linux</strong> 直接用；<strong>Windows</strong> 用 PowerShell 把 <code>mkdir -p</code> 换成 <code>mkdir</code>，或在资源管理器里手动建文件夹。<code>~</code> 指用户主目录，Windows 对应 <code>C:\\Users\\你的用户名\\</code> 。还没装 Codex 的回第 03 篇装好再来。本节命令、目录均以官方文档为准；个别交互界面随版本会变，<strong>以你本地实际显示为准</strong>。</p></blockquote><h3 id="第一步-建用户级技能目录" tabindex="-1">第一步：建用户级技能目录 <a class="header-anchor" href="#第一步-建用户级技能目录" aria-label="Permalink to &quot;第一步：建用户级技能目录&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.agents/skills/explain-self</span></span></code></pre></div><p><strong>预期</strong>：<code>~/.agents/skills/</code> 下多了个 <code>explain-self</code> 空目录。<strong>注意是 <code>.agents</code> 不是 <code>.codex</code></strong>——这就是第 04 节反复强调的那个坑，亲手建对一次记得最牢。</p><h3 id="第二步-写一个最简单的-skill-md" tabindex="-1">第二步：写一个最简单的 <code>SKILL.md</code> <a class="header-anchor" href="#第二步-写一个最简单的-skill-md" aria-label="Permalink to &quot;第二步：写一个最简单的 `SKILL.md`&quot;">​</a></h3><p>用你顺手的编辑器，把下面内容存到 <code>~/.agents/skills/explain-self/SKILL.md</code> ：</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">explain-self</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">用大白话解释一段代码或一个报错。当用户说「这段代码啥意思」「这个报错咋回事」「帮我读读这个」时使用。</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">把用户给的代码或报错，用初学者能懂的大白话讲清楚：</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 这东西整体在干啥（一句话）</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 逐行 / 逐段拆开说</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 如果是报错，指出最可能的原因和怎么改</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">不要堆术语，能用生活类比就用。</span></span></code></pre></div><p>注意它的 <code>description</code> 特意写了「这段代码啥意思」「这个报错咋回事」这些<strong>你真会说出口的话</strong>——这就是第 03 节讲的「隐式匹配的钩子」。</p><p><strong>预期</strong>：<code>explain-self</code> 目录里有了一个 <code>SKILL.md</code> 。</p><h3 id="第三步-启动-codex-确认它认得这个-skill" tabindex="-1">第三步：启动 Codex，确认它认得这个 Skill <a class="header-anchor" href="#第三步-启动-codex-确认它认得这个-skill" aria-label="Permalink to &quot;第三步：启动 Codex，确认它认得这个 Skill&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span></span></code></pre></div><p>进去后跑：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/skills</span></span></code></pre></div><p><strong>预期</strong>：弹出的技能选择器里，能看到 <code>explain-self</code> ，旁边是你写的那句描述。<strong>看到它在列表里 = Skill 已被正确发现。</strong> 这一步也顺带印证了渐进式披露：此刻上下文里只有它这<strong>一句描述 + 名字 + 路径</strong>，正文那几行说明还没被加载进来。</p><h3 id="第四步-不点名-用「人话」隐式触发它" tabindex="-1">第四步：不点名，用「人话」隐式触发它 <a class="header-anchor" href="#第四步-不点名-用「人话」隐式触发它" aria-label="Permalink to &quot;第四步：不点名，用「人话」隐式触发它&quot;">​</a></h3><p>故意<strong>不打</strong> <code>$explain-self</code> ，而是说一句对得上描述的话：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这段代码啥意思：print(sum([1,2,3]) / len([1,2,3]))</span></span></code></pre></div><p><strong>预期</strong>：Codex 隐式匹配上 <code>explain-self</code> 这个 Skill（你压根没提它的名字，是它自己对上描述的），然后按你写的三步——先一句话说整体（算这三个数的平均值，结果是 2.0）、再逐段拆、术语少——来解释。<strong>它没等你喊就把对应本事调出来了，这就是隐式调用。</strong></p><h3 id="第五步-对比-显式点名" tabindex="-1">第五步：对比 <code>$</code> 显式点名 <a class="header-anchor" href="#第五步-对比-显式点名" aria-label="Permalink to &quot;第五步：对比 `$` 显式点名&quot;">​</a></h3><p>再试一次显式档，打一个 <code>$</code> 把它点出来：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$explain-self 这个报错咋回事：ZeroDivisionError: division by zero</span></span></code></pre></div><p><strong>预期</strong>：同样触发这个 Skill，效果和第四步一致——区别只在于这次是你<strong>主动点名</strong>的，Codex 不做匹配判断、直接照单全收。两条路通向同一身本事，正好印证第 03 节那张表。</p><p>跑通这五步，你就把 Skill 最核心的几件事——<strong>放对目录（<code>.agents</code> 不是 <code>.codex</code>）、描述匹配隐式触发、<code>$</code> 显式点名、平时只占一行描述</strong>——亲手验证了一遍，比记十条文档都实在。</p><blockquote><p>💡 一句话总结：在 <code>~/.agents/skills/explain-self/SKILL.md</code> 写个最小技能、用 <code>/skills</code> 确认发现、再用「人话」和 <code>$名字</code> 各触发一次——<strong>亲眼看到隐式和显式通向同一身本事，还顺手避开了「目录建错到 <code>.codex</code>」这个最常见的坑</strong>。</p></blockquote><hr><h2 id="_07-小结" tabindex="-1">07 小结 <a class="header-anchor" href="#_07-小结" aria-label="Permalink to &quot;07 小结&quot;">​</a></h2><p>这一篇把 Agent Skills 从「是什么」到「怎么上手」捋了一遍——<strong>它让 Codex 不再是张白纸，而是带着一身能按需调出的专项本事上岗</strong>。</p><p>核心要点串起来回顾：</p><table tabindex="0"><thead><tr><th>主题</th><th>答案</th><th>关键点</th></tr></thead><tbody><tr><td>Skill 是什么</td><td>带 <code>SKILL.md</code> 的目录 + 可选脚本 / 参考</td><td>frontmatter 必须有 <code>name</code> + <code>description</code></td></tr><tr><td>为什么不撑上下文</td><td>渐进式披露</td><td>平时只露名称 + 描述，用到才展开正文；初始清单约 2% / 8000 字符预算</td></tr><tr><td>怎么触发</td><td>显式 / 隐式两种</td><td><code>$</code> 或 <code>/skills</code> 点名；或按 <code>description</code> 自动匹配</td></tr><tr><td>放哪</td><td><code>.agents/skills</code> 那套</td><td>仓库级 / 用户级 <code>$HOME/.agents/skills</code>，<strong>不是 <code>~/.codex/skills</code></strong></td></tr><tr><td>怎么上手</td><td>造 / 装 / 禁用</td><td><code>$skill-creator</code>、<code>$skill-installer</code>、<code>[[skills.config]]</code></td></tr></tbody></table><p><strong>你现在应该能：</strong> 说清一个 Skill 由什么组成、它凭「渐进式披露」省上下文的原理；分得清显式 <code>$</code> 点名和隐式描述匹配两种触发、知道隐式准不准全压在 <code>description</code> 上；记住技能放 <code>.agents/skills</code>（而不是 <code>~/.codex/skills</code>）、同名会并列不合并；并且会用 <code>$skill-creator</code> 三五句话生成一个、用 <code>[[skills.config]]</code> 临时禁掉一个。<strong>这套「把反复交代的活儿封成一项能力」的本事，是你把 Codex 从『通用助手』调教成『懂你这套流程的专家』的关键一步。</strong></p><p>几条最容易踩的坑，临走再钉一遍：<strong>自己手写的 Skill 走 <code>.agents/skills</code>（不要手动塞进 <code>~/.codex/skills/</code>）、<code>$skill-installer</code> 装的精选 Skill 由它自己放在 <code>~/.codex/skills/</code>、字段没有 <code>trigger</code>、显式调用是 <code>$</code> 不是 <code>@</code></strong>——这几点凡是跟你看过的某些老教程对不上的，<strong>以官方为准</strong>。</p><hr><p>下一篇 <strong>〔<a href="./23-plugins">23 插件（Plugins）</a> 〕</strong>——这一篇你学会了把一套活儿封成 Skill，可它默认只在你自己机器、你自己仓库里转。要是想把这身本事<strong>打包好、让队友或社区一键装上</strong>呢？官方给的答案就是 Plugins——「Skill 是编写格式，Plugin 是分发格式」。下一篇就讲怎么把一个或多个 Skill 连同配置一起打成插件、装到别人那儿去。留个小思考：你这一篇写的 <code>explain-self</code>，要是想让整个团队都用上，光提交进仓库够不够，还差哪一步？</p>',126)])])}const u=e(i,[["render",n]]);export{h as __pageData,u as default};
